type WebResponse = 
  | { type: "error"; message: string }
  | { type: "success"; data: any };

function handle(res: WebResponse) {
  switch(res.type) {
    case "error": return res.message;
    case "success": return "Data loaded";
  }
}

async function loadBalance(id: string): Promise<number> {
  const user = await database.getUser(id);
  return user.balance;
}

